sql:
SELECT AVG(value) AS average_value
FROM data
WHERE series_id = 1 AND start_date BETWEEN '2023-01-01' AND '2023-03-31';

SELECT value
FROM data
WHERE series_id = 0 AND start_date = '2023-01-01';

SELECT domain_name
FROM domains
WHERE domain_id = 1;

SELECT domain_name 
FROM domains 
WHERE last_updated = '2023-10-01 12:00:00';

external_knowledge:
- 'ocean waves' metaphorically represents the series data;
- 'quarterly fiscal sea' refers to the periodicity being 'Quarterly';
- '10,000-meter mark' translates to an average value greater than 10,000;
- 'whisper their names' is a poetic way of saying 'the series names will be revealed';
- 'winds of Banco de Portugal' metaphorically refers to the source of the data.

sql:
SELECT COUNT(*) AS total_data_points
FROM data
WHERE series_id = 0;

SELECT collection_method, COUNT(domain_id) AS domain_count
FROM domains
GROUP BY collection_method;

SELECT COUNT(s.series_id) AS series_count, GROUP_CONCAT(s.series_name) AS series_names
FROM series s
WHERE s.functional_category_id = 0;
